UPDATE public.questions SET
  stimulus_text = 'The author suggests that the development of the smartphone has changed how people connect with each other. In the past, people relied on personal interactions to build connections. However, the smartphone has allowed people to connect with each other in ways that were not possible before. As a result, the author argues, the smartphone has created new opportunities for people to build connections.  According to the author, what has changed how people connect with each other?',
